import{_ as t,o as a,c as r,ao as o}from"./chunks/framework.DfGcrnLH.js";const s=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":null}'),i={name:"changelog.md"};function l(n,e,u,h,d,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="Changelog" tabindex="-1">Changelog <a class="header-anchor" href="#Changelog" aria-label="Permalink to &quot;Changelog {#Changelog}&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="Guidelines-for-updating-this-changelog" tabindex="-1">Guidelines for updating this changelog <a class="header-anchor" href="#Guidelines-for-updating-this-changelog" aria-label="Permalink to &quot;Guidelines for updating this changelog {#Guidelines-for-updating-this-changelog}&quot;">​</a></h2><p>When making changes to this project, please update the &quot;Unreleased&quot; section with your changes under the appropriate category:</p><ul><li><p><strong>Added</strong> for new features.</p></li><li><p><strong>Changed</strong> for changes in existing functionality.</p></li><li><p><strong>Deprecated</strong> for soon-to-be removed features.</p></li><li><p><strong>Removed</strong> for now removed features.</p></li><li><p><strong>Fixed</strong> for any bug fixes.</p></li></ul><p>When releasing a new version, move the &quot;Unreleased&quot; changes to a new version section with the release date.</p><h2 id="Unreleasedhttps://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.11...HEAD" tabindex="-1"><a href="https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.11...HEAD" target="_blank" rel="noreferrer">Unreleased</a> <a class="header-anchor" href="#Unreleasedhttps://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.11...HEAD" aria-label="Permalink to &quot;[Unreleased](https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.11...HEAD) {#Unreleasedhttps://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.11...HEAD}&quot;">​</a></h2><h3 id="Added" tabindex="-1">Added <a class="header-anchor" href="#Added" aria-label="Permalink to &quot;Added {#Added}&quot;">​</a></h3><h3 id="Changed" tabindex="-1">Changed <a class="header-anchor" href="#Changed" aria-label="Permalink to &quot;Changed {#Changed}&quot;">​</a></h3><ul><li><code>environments</code> now follows a single positional contract for every state and operator kind: <code>environments(below, operator, above, alg)</code>, where <code>alg</code> is the environment algorithm (slot 4). The operator form requires an explicit <code>above</code>. Auxiliary inputs are keyword-only: <code>leftstart</code>/<code>rightstart</code> for finite and window environments, and <code>lenvs</code>/<code>renvs</code> for window and quasiparticle environments. The two-argument form <code>environments(below, above)</code> (with two states) is reserved for the operator-free overlap environments. There is no two-argument <code>environments(below, operator)</code> shorthand: a two-argument call is always the overlap, since the second argument cannot be disambiguated between a ket and an operator (undecidable for density matrices, where states and operators share a representation). (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/436" target="_blank" rel="noreferrer">#436</a>)</li></ul><h3 id="Deprecated" tabindex="-1">Deprecated <a class="header-anchor" href="#Deprecated" aria-label="Permalink to &quot;Deprecated {#Deprecated}&quot;">​</a></h3><h3 id="Removed" tabindex="-1">Removed <a class="header-anchor" href="#Removed" aria-label="Permalink to &quot;Removed {#Removed}&quot;">​</a></h3><h3 id="Fixed" tabindex="-1">Fixed <a class="header-anchor" href="#Fixed" aria-label="Permalink to &quot;Fixed {#Fixed}&quot;">​</a></h3><h3 id="Performance" tabindex="-1">Performance <a class="header-anchor" href="#Performance" aria-label="Permalink to &quot;Performance {#Performance}&quot;">​</a></h3><h2 id="0.13.11https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.10...v0.13.11-2026-05-04" tabindex="-1"><a href="https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.10...v0.13.11" target="_blank" rel="noreferrer">0.13.11</a> - 2026-05-04 <a class="header-anchor" href="#0.13.11https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.10...v0.13.11-2026-05-04" aria-label="Permalink to &quot;[0.13.11](https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.10...v0.13.11) - 2026-05-04 {#0.13.11https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.10...v0.13.11-2026-05-04}&quot;">​</a></h2><h3 id="Added-2" tabindex="-1">Added <a class="header-anchor" href="#Added-2" aria-label="Permalink to &quot;Added {#Added-2}&quot;">​</a></h3><ul><li><code>MultilineMPO</code> space getters (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/407" target="_blank" rel="noreferrer">#407</a>)</li></ul><h3 id="Changed-2" tabindex="-1">Changed <a class="header-anchor" href="#Changed-2" aria-label="Permalink to &quot;Changed {#Changed-2}&quot;">​</a></h3><ul><li><p>Refactored time-evolution MPO construction (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/422" target="_blank" rel="noreferrer">#422</a>)</p></li><li><p>Updated <code>TensorKitManifolds</code> compat to 0.8 (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/421" target="_blank" rel="noreferrer">#421</a>)</p></li><li><p>Updated MatrixAlgebraKit algorithm specification (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/418" target="_blank" rel="noreferrer">#418</a>)</p></li><li><p>Preparations for GPU / non-CPU array support (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/375" target="_blank" rel="noreferrer">#375</a>, <a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/392" target="_blank" rel="noreferrer">#392</a>)</p></li><li><p>Generalized <code>calc_galerkin</code> to <code>AbstractMPS</code> (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/395" target="_blank" rel="noreferrer">#395</a>)</p></li><li><p>Removed explicit call to <code>InfiniteMPS</code> in VUMPS (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/396" target="_blank" rel="noreferrer">#396</a>)</p></li><li><p>Generalized <code>regauge!</code> to <code>AbstractVector</code> (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/393" target="_blank" rel="noreferrer">#393</a>)</p></li></ul><h3 id="Fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#Fixed-2" aria-label="Permalink to &quot;Fixed {#Fixed-2}&quot;">​</a></h3><ul><li><p>Various fixes for compatibility with latest TensorKit versions (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/416" target="_blank" rel="noreferrer">#416</a>)</p></li><li><p><code>changebonds</code> inconsistencies (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/415" target="_blank" rel="noreferrer">#415</a>)</p></li><li><p>Small fixes for density operators (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/409" target="_blank" rel="noreferrer">#409</a>)</p></li><li><p>Tolerance on positivity test (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/398" target="_blank" rel="noreferrer">#398</a>)</p></li></ul><h3 id="Performance-2" tabindex="-1">Performance <a class="header-anchor" href="#Performance-2" aria-label="Permalink to &quot;Performance {#Performance-2}&quot;">​</a></h3><ul><li>Benchmarks and AC/AC2 contraction improvements (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/345" target="_blank" rel="noreferrer">#345</a>)</li></ul><h2 id="0.13.10https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.9...v0.13.10-2026-02-26" tabindex="-1"><a href="https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.9...v0.13.10" target="_blank" rel="noreferrer">0.13.10</a> - 2026-02-26 <a class="header-anchor" href="#0.13.10https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.9...v0.13.10-2026-02-26" aria-label="Permalink to &quot;[0.13.10](https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.9...v0.13.10) - 2026-02-26 {#0.13.10https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.9...v0.13.10-2026-02-26}&quot;">​</a></h2><h3 id="Added-3" tabindex="-1">Added <a class="header-anchor" href="#Added-3" aria-label="Permalink to &quot;Added {#Added-3}&quot;">​</a></h3><ul><li><p><code>expectation_value</code> for local MPO tensors (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/327" target="_blank" rel="noreferrer">#327</a>)</p></li><li><p><code>Base.copy</code> for MPS types now performs a deep copy (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/387" target="_blank" rel="noreferrer">#387</a>)</p></li></ul><h3 id="Changed-3" tabindex="-1">Changed <a class="header-anchor" href="#Changed-3" aria-label="Permalink to &quot;Changed {#Changed-3}&quot;">​</a></h3><ul><li><p><code>entropy</code> can now also be called directly on a spectrum (singular value vector) (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/377" target="_blank" rel="noreferrer">#377</a>)</p></li><li><p>Updated compat bounds to remove broken package versions</p></li></ul><h3 id="Fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#Fixed-3" aria-label="Permalink to &quot;Fixed {#Fixed-3}&quot;">​</a></h3><ul><li>Fixed <code>Adapt</code> extension for GPU support (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/389" target="_blank" rel="noreferrer">#389</a>)</li></ul><h2 id="0.13.9https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.8...v0.13.9-2026-02-03" tabindex="-1"><a href="https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.8...v0.13.9" target="_blank" rel="noreferrer">0.13.9</a> - 2026-02-03 <a class="header-anchor" href="#0.13.9https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.8...v0.13.9-2026-02-03" aria-label="Permalink to &quot;[0.13.9](https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.8...v0.13.9) - 2026-02-03 {#0.13.9https://github.com/QuantumKitHub/MPSKit.jl/compare/v0.13.8...v0.13.9-2026-02-03}&quot;">​</a></h2><h3 id="Added-4" tabindex="-1">Added <a class="header-anchor" href="#Added-4" aria-label="Permalink to &quot;Added {#Added-4}&quot;">​</a></h3><ul><li><p><code>LocalPreferences.toml</code> file to ensure <code>TensorOperations</code> properly precompiles on testing infrastructure</p></li><li><p><code>GeometryStyle</code> and <code>OperatorStyle</code> traits for dispatching on finite/infinite geometry and operator types (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/352" target="_blank" rel="noreferrer">#352</a>, <a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/354" target="_blank" rel="noreferrer">#354</a>)</p></li><li><p><code>Base.isfinite</code> methods for MPS types (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/347" target="_blank" rel="noreferrer">#347</a>)</p></li><li><p>Bose-Hubbard example (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/342" target="_blank" rel="noreferrer">#342</a>)</p></li><li><p>WindowMPS example update (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/350" target="_blank" rel="noreferrer">#350</a>)</p></li><li><p>Multifusion category compatibility (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/297" target="_blank" rel="noreferrer">#297</a>)</p></li></ul><h3 id="Fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#Fixed-4" aria-label="Permalink to &quot;Fixed {#Fixed-4}&quot;">​</a></h3><ul><li><p>Dynamic tolerances yielded <code>NaN</code> during the initialization stage due to <code>1 / sqrt(iter)</code> where <code>iter = 0</code> (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/335" target="_blank" rel="noreferrer">#335</a>)</p></li><li><p><code>InfiniteMPOHamiltonian</code> environments with low bond dimension and high Krylov dimension now are properly clamped (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/335" target="_blank" rel="noreferrer">#335</a>)</p></li><li><p>Logical operator precedence in <code>getproperty</code> function (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/346" target="_blank" rel="noreferrer">#346</a>)</p></li><li><p>Typo in <code>VUMPSSvdCut</code> (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/361" target="_blank" rel="noreferrer">#361</a>)</p></li><li><p>Typo in time formatting for logs (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/336" target="_blank" rel="noreferrer">#336</a>)</p></li><li><p>Domain/codomain of <code>MPODerivativeOperator</code> (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/370" target="_blank" rel="noreferrer">#370</a>)</p></li><li><p>In-place operations handled more carefully (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/337" target="_blank" rel="noreferrer">#337</a>)</p></li><li><p>Orthogonalization algorithms now use correct methods (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/373" target="_blank" rel="noreferrer">#373</a>)</p></li></ul><h3 id="Changed-4" tabindex="-1">Changed <a class="header-anchor" href="#Changed-4" aria-label="Permalink to &quot;Changed {#Changed-4}&quot;">​</a></h3><ul><li><p>The <code>changebonds(state, ::RandExpand)</code> algorithm now no longer has to perform a truncated SVD to obtain the desired spaces, and instead sample the space directly and then generates a random isometry. This should be slightly more performant, but otherwise equivalent (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/335" target="_blank" rel="noreferrer">#335</a>)</p></li><li><p><code>IDMRG</code> refactored to follow the <code>IterativeSolver</code> interface and share code between <code>IDMRG</code> and <code>IDMRG2</code> (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/348" target="_blank" rel="noreferrer">#348</a>)</p></li><li><p>Bumped compatibility for TensorKit 0.16 and MatrixAlgebraKit 0.6 (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/365" target="_blank" rel="noreferrer">#365</a>)</p></li><li><p>Removed <code>_left_orth</code> and <code>_right_orth</code> workarounds in favor of new orthogonalization methods</p></li><li><p>Reduced allocation while computing Galerkin error (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/366" target="_blank" rel="noreferrer">#366</a>)</p></li><li><p>Updated <code>show</code> methods to reflect new TensorKit printing (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/341" target="_blank" rel="noreferrer">#341</a>)</p></li><li><p>More informative errors for finite MPS (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/367" target="_blank" rel="noreferrer">#367</a>)</p></li><li><p>Minor documentation and docstring improvements (<a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/363" target="_blank" rel="noreferrer">#363</a>, <a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/372" target="_blank" rel="noreferrer">#372</a>, <a href="https://github.com/QuantumKitHub/MPSKit.jl/pull/371" target="_blank" rel="noreferrer">#371</a>)</p></li></ul><h3 id="Deprecated-2" tabindex="-1">Deprecated <a class="header-anchor" href="#Deprecated-2" aria-label="Permalink to &quot;Deprecated {#Deprecated-2}&quot;">​</a></h3><h3 id="Removed-2" tabindex="-1">Removed <a class="header-anchor" href="#Removed-2" aria-label="Permalink to &quot;Removed {#Removed-2}&quot;">​</a></h3><h2 id="0.13.8https://github.com/QuantumKitHub/MPSKit.jl/releases/tag/v0.13.8-2024-10-31" tabindex="-1"><a href="https://github.com/QuantumKitHub/MPSKit.jl/releases/tag/v0.13.8" target="_blank" rel="noreferrer">0.13.8</a> - 2024-10-31 <a class="header-anchor" href="#0.13.8https://github.com/QuantumKitHub/MPSKit.jl/releases/tag/v0.13.8-2024-10-31" aria-label="Permalink to &quot;[0.13.8](https://github.com/QuantumKitHub/MPSKit.jl/releases/tag/v0.13.8) - 2024-10-31 {#0.13.8https://github.com/QuantumKitHub/MPSKit.jl/releases/tag/v0.13.8-2024-10-31}&quot;">​</a></h2><p>See full history and previous releases on <a href="https://github.com/QuantumKitHub/MPSKit.jl/releases" target="_blank" rel="noreferrer">GitHub</a>.</p>',42)])])}const m=t(i,[["render",l]]);export{s as __pageData,m as default};
